const opcion = String(ctx.menu_selection_option || "").trim();
const menuOptions = (ctx.menu_options) || (ctx.bot_config && ctx.bot_config.menu && ctx.bot_config.menu.options) || [];
const selected = menuOptions.find(function(o) { return o.id === opcion; });
if (!selected) {
  // Invalid option - show menu again
  return [{ json: Object.assign({}, ctx, { intent: "MENU", classified_by: "MENU_INVALID", skip_ai: true }) }];
}
const out = Object.assign({}, ctx, {
  intent: selected.intent,
  classified_by: "MENU_SELECTION_RESOLVED",
  skip_ai: true
});
// For INFO options, use predefined query instead of original message
if (selected.intent === "INFO" && selected.query) {
  out.message_text = selected.query;
}
return [{ json: out }];

const ctx = $input.first().json;
const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
const phone     = ctx.contact_phone || "";
const clinicId  = ctx.clinic_id || "";

if (!phone) {
  return [{ json: Object.assign({}, ctx, { raw_appointments: [], has_appointments: false, phone_missing: true }) }];
}

let appointments = [];
const fields = "select=id,start_time,end_time,service,status,patient_name";
const base   = SUPABASE_URL + "/rest/v1/appointments";
const hdrs   = { apikey: SERVICE_KEY, Authorization: "Bearer " + SERVICE_KEY };

// Try contact_phone field first, then phone field
const queries = [
  base + "?contact_phone=eq." + encodeURIComponent(phone) + "&clinic_id=eq." + clinicId + "&status=neq.cancelled&order=start_time.asc&limit=5&" + fields,
  base + "?phone=eq."         + encodeURIComponent(phone) + "&clinic_id=eq." + clinicId + "&status=neq.cancelled&order=start_time.asc&limit=5&" + fields
];

for (var qi = 0; qi < queries.length; qi++) {
  try {
    const res = await this.helpers.httpRequest({ method: "GET", url: queries[qi], headers: hdrs, json: true });
    if (res && res.length > 0) { appointments = res; break; }
  } catch(e) { /* try next */ }
}

return [{ json: Object.assign({}, ctx, { raw_appointments: appointments, has_appointments: appointments.length > 0 }) }];

const ctx = $input.first().json;
const appts = ctx.raw_appointments || [];
const clinicName = ctx.clinic_name || "la clinica";

if (!appts || appts.length === 0) {
  var noApptText = "";
  if (ctx.phone_missing) {
    noApptText = "No pude identificar tu numero de telefono. Por favor contacta directamente a la clinica.";
  } else {
    noApptText = "No encontre citas programadas para tu numero en " + clinicName + ".\n\nPara agendar una nueva cita responde *1* o escribe \"quiero una cita\".";
  }
  return [{ json: Object.assign({}, ctx, { appointments_text: noApptText }) }];
}

var lines = appts.map(function(a, i) {
  var dt     = new Date(a.start_time);
  var fecha  = dt.toLocaleDateString("es-PE", { weekday: "long", day: "numeric", month: "long" });
  var hora   = dt.toLocaleTimeString("es-PE", { hour: "2-digit", minute: "2-digit" });
  var serv   = a.service || "Consulta general";
  var estado = a.status === "scheduled" ? "Confirmada ✅" : a.status;
  var shortId = a.id ? a.id.slice(0, 8) : "---";
  return (i + 1) + ". *" + fecha + "* a las " + hora + "\n   Servicio: " + serv + "\n   Estado: " + estado;
});

var text = "📋 *Tus citas en " + clinicName + ":*\n\n" + lines.join("\n\n");
text += "\n\n_Para cancelar una cita escribe: cancelar [numero]_\n_Ej: cancelar 1_";
text += "\n\nPara agendar una nueva cita responde *1*.";

return [{ json: Object.assign({}, ctx, { appointments_text: text }) }];

// RESOLVER DOCTOR — busca doctores activos de la clínica y hace match con preferencia del paciente
// Si no hay doctores → fallback a modo clínica (igual que antes)
const ctx = $("Explicar Agendamiento").item.json;
const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
const clinic_id    = ctx.clinic_id;

var doctors = [];
try {
  doctors = await this.helpers.httpRequest({
    method: "GET",
    url: SUPABASE_URL + "/rest/v1/rpc/list_doctors",
    headers: { apikey: SERVICE_KEY, Authorization: "Bearer " + SERVICE_KEY, "Content-Type": "application/json" },
    body: { p_clinic_id: clinic_id },
    json: true
  });
  if (!Array.isArray(doctors)) doctors = [];
} catch(e) {
  console.warn(JSON.stringify({ ts: new Date().toISOString(), event: "DOCTORS_FETCH_ERROR", error: e.message }));
  doctors = [];
}

// Match doctor by name or specialty
var preferred_name = (ctx.preferred_doctor_name || "").toLowerCase().trim();
var preferred_spec = (ctx.preferred_specialty   || "").toLowerCase().trim();
var selected_doctor = null;

if (preferred_name && doctors.length > 0) {
  // Try last name first, then full name
  selected_doctor = doctors.find(function(d) {
    var full = (d.first_name + " " + d.last_name).toLowerCase();
    var last = d.last_name.toLowerCase();
    return last.includes(preferred_name) || preferred_name.includes(last) || full.includes(preferred_name);
  }) || null;
}

if (!selected_doctor && preferred_spec && doctors.length > 0) {
  selected_doctor = doctors.find(function(d) {
    return d.specialty.toLowerCase().includes(preferred_spec);
  }) || null;
}

console.log(JSON.stringify({
  ts: new Date().toISOString(),
  event: "DOCTOR_RESOLVED",
  total_doctors: doctors.length,
  selected: selected_doctor ? selected_doctor.last_name : null,
  mode: selected_doctor ? "specific" : (doctors.length > 0 ? "any" : "legacy")
}));

return [{ json: Object.assign({}, ctx, {
  available_doctors: doctors,
  selected_doctor: selected_doctor,
  doctor_selection_mode: selected_doctor ? "specific" : (doctors.length > 0 ? "any" : "legacy")
}) }];

// ============================================
// VALIDAR INPUT + DETECTAR CONTACTO NUEVO
// ============================================
const payload = $input.item.json.body || $input.item.json;

// Campos del evento
const event = payload.event;
const content = payload.content || '';
const conversation_id = payload.conversation?.id;
const inbox_id = payload.conversation?.inbox_id;
const clinic_id = payload.conversation?.custom_attributes?.clinic_id;
const patient_id = payload.conversation?.custom_attributes?.patient_id;
const contact_phone = payload.conversation?.contact_inbox?.source_id;
const contact_id = payload.sender?.id;
const channel_type = payload.conversation?.contact_inbox?.inbox?.channel_type;
const account_id = payload.account?.id || 2;
const message_type = payload.message_type;
const created_at = payload.created_at;

// Obtener contador de interacciones bot
const bot_count = payload.conversation?.custom_attributes?.bot_interaction_count || 0;
const last_bot_message = payload.conversation?.custom_attributes?.last_bot_message_at;
const contact_inboxes = payload.conversation?.contact_inbox;
const has_contact_inbox = !!contact_inboxes;

return [{
  json: {
    message_text: (content || '').trim(),
    conversation_id: conversation_id,
    inbox_id: inbox_id,
    inbox_id_api: 2,
    inbox_id_db: 3,
    clinic_id: clinic_id || 'default',
    patient_id: patient_id,
    contact_phone: contact_phone,
    contact_id: contact_id,
    account_id: account_id,
    message_type: message_type,
    message_timestamp: created_at,
    bot_interaction_count: bot_count,
    last_bot_message_at: last_bot_message,
    sender_name: payload.sender?.name || 'Paciente',
    sender_email: payload.sender?.email,
    conversation_status: payload.conversation?.status,
    has_contact_inbox: has_contact_inbox,
    channel_type: channel_type || 'Channel::WebWidget',
    raw_payload: payload
  }
}];

// WHATSAPP SAFE RULES - FASE 1
const ctx           = $input.first().json;
const bot_count     = ctx.bot_interaction_count || 0;
const message_lower = (ctx.message_text || "").toLowerCase();

// Regla 1: Maximo 10 interacciones automaticas
if (bot_count >= 10) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "MAX_INTERACTIONS_PHASE1",
    escalation_message: "Te conecto con un agente de inmediato." } }];
}

// Regla 2: Mensaje > 24h
const message_age_hours = (Date.now() - (ctx.message_timestamp * 1000)) / 3600000;
if (message_age_hours > 24) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "MESSAGE_TOO_OLD",
    escalation_message: "Te conecto con un agente." } }];
}

// Regla 3: Horario comercial Lima (8am - 10pm)
const now = new Date();
const lima_hour = parseInt(now.toLocaleString("en-US", { timeZone: "America/Lima", hour: "numeric", hour12: false }));
if (lima_hour < 8 || lima_hour >= 22) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "OUTSIDE_BUSINESS_HOURS",
    escalation_message: "Gracias por escribirnos. Te responderemos en horario de atencion (8am - 10pm)." } }];
}

// Regla 4: Emergencias
const emergency_kws = ["emergencia","urgencia","urgente","dolor fuerte","sangra","mucho dolor","me duele mucho","duele mucho","muela","golpe","accidente","hinchazon","infeccion","inflamacion","fiebre"];
if (emergency_kws.some(function(kw) { return message_lower.includes(kw); })) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "EMERGENCY_DETECTED",
    escalation_message: "Detecto que podrias tener una urgencia. Te conecto de inmediato.", priority: "urgent" } }];
}

// Regla 5: Opt-out
const opt_out_kws = ["detente","ya no","basta","stop","cancelar bot","agente","humano","persona"];
if (opt_out_kws.some(function(kw) { return message_lower.includes(kw); })) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "USER_OPT_OUT",
    escalation_message: "Entendido. Te conecto con un agente humano." } }];
}

// Todo OK - continuar al clasificador
return [{ json: { ...ctx, should_escalate: false, whatsapp_safe: true,
  debug_bot_count: bot_count, debug_lima_hour: lima_hour, checked_at: new Date().toISOString() } }];

// NORMALIZAR OUTPUT DEL CLASIFICADOR
// Keyword path: context is intact in $json
if ($json.skip_ai === true && $json.intent) {
    const intent = $json.intent;
    // GREETING is now handled by ¿Es MENU o GREETING? — do NOT convert to INFO
    return [{ json: Object.assign({}, $json, { intent: intent, classified_at: new Date().toISOString(), phase: "PHASE_1_WITH_PRE_CLASSIFIER" }) }];
}

// AI path: restore context from Pre-Clasificador Keywords node
const ctx = $node["Pre-Clasificador Keywords"].json;
let intent_data = $json.output || $json;
if (typeof intent_data === "string") {
    try { intent_data = JSON.parse(intent_data); }
    catch(e) {
        const t = intent_data.toLowerCase();
        if (t.includes("create_event")) intent_data = { intent: "CREATE_EVENT", confidence: "low" };
        else if (t.includes("info"))   intent_data = { intent: "INFO",         confidence: "low" };
        else if (t.includes("payment")) intent_data = { intent: "PAYMENT",     confidence: "low" };
        else intent_data = { intent: "HUMAN", confidence: "low" };
    }
}
let intent = (intent_data.intent || "HUMAN").trim().toUpperCase();
let confidence = (intent_data.confidence || "low").toLowerCase();
const valid = ["CREATE_EVENT","INFO","PAYMENT","HUMAN"];
if (!valid.includes(intent)) { intent = "HUMAN"; confidence = "low"; }
return [{ json: Object.assign({}, ctx, { intent: intent, confidence: confidence, classified_at: new Date().toISOString(), phase: "PHASE_1_WITH_AI_CLASSIFIER" }) }];

// Preservar TODOS los datos del input
return [{
  json: {
    ...$json,
    escalation_message_final: $json.escalation_message || 'Te conecto con un agente de nuestro equipo.',
    escalation_reason_final: $json.escalation_reason || 'PHASE_1_' + $json.intent,
    internal_note: 'SofIA (Fase 1) - Intent: ' + $json.intent,
    is_urgent: $json.priority === 'urgent'
  }
}];

const message_text = $json.message_text || "";
const clinic_name = $json.clinic_name || "la clinica";
const isGreeting = $json.is_greeting === true;
const welcomeMsg = $json.welcome_message_text || ("Hola! Soy SofIA de " + clinic_name + ". En que puedo ayudarte?");
const kb_context = $json.kb_context || "";
var system_prompt, user_prompt;

if (isGreeting) {
    system_prompt = "Eres SofIA, asistente virtual de " + clinic_name + ". El paciente te saludo. Responde EXACTAMENTE con: \"" + welcomeMsg + "\" No agregues nada mas.";
    user_prompt = message_text;
} else {
    var rules = [
        "1. Se amable y directo, maximo 2-3 oraciones",
        "2. Responde en espanol",
        "3. Si el paciente pregunta sobre disponibilidad o si puede ir un dia especifico, SIEMPRE dile que escriba: quiero una cita el [dia] y la verificaras inmediatamente",
        "4. Si tienes la informacion en el contexto, usala. Si no, di honestamente que no tienes ese dato y ofrece conectarlo con un agente",
        "5. NUNCA prometas algo que no puedes cumplir",
        "6. NO uses frases vagas como te recomiendo agendar una cita. Se especifico sobre el siguiente paso"
    ].join(". ");
    var kbSection = kb_context ? "INFORMACION DE LA CLINICA:\n" + kb_context + "\n\n" : "";
    system_prompt = "Eres SofIA, asistente virtual de la clinica dental " + clinic_name + ". " + kbSection + "REGLAS: " + rules;
    user_prompt = message_text;
}

return [{ json: Object.assign({}, $json, { system_prompt: system_prompt, user_prompt: user_prompt }) }];

// Extraer respuesta del LLM
const response = $json;

// La respuesta de OpenAI viene en response.choices[0].message.content
const llm_response = response.choices?.[0]?.message?.content || '';

// Obtener datos originales del nodo "Preparar Prompt INFO"
const original_data = $node["Preparar Prompt INFO"].json;

return [{
  json: {
    ...original_data,  // Todos los datos originales (conversation_id, account_id, etc.)
    llm_response: llm_response.trim()
  }
}];

// ============================================
// VALIDACION ANTI-ALUCINACION
// ============================================

const llm_response = $json.llm_response || '';

// Flags de validación
let should_escalate = false;
let escalation_reason = '';

// Regla 1: Respuesta muy larga (>500 chars)
if (llm_response.length > 500) {
  should_escalate = true;
  escalation_reason = 'Respuesta LLM muy larga (>500 chars)';
}

// Regla 2: LLM dice que no tiene información
const no_info_keywords = [
  'no tengo esa información',
  'no dispongo',
  'no cuento con',
  'no tengo información',
  'no está disponible',
  'te conecto con un agente'
];

for (const keyword of no_info_keywords) {
  if (llm_response.toLowerCase().includes(keyword)) {
    should_escalate = true;
    escalation_reason = 'LLM indica falta de información';
    break;
  }
}

// Regla 3: Respuesta vacía o muy corta
if (llm_response.length < 10) {
  should_escalate = true;
  escalation_reason = 'Respuesta LLM vacía o muy corta';
}

return [{
  json: {
    ...($json || {}),
    should_escalate_info: should_escalate,
    escalation_reason_info: escalation_reason,
    validation_passed: !should_escalate
  }
}];

// EXPLICAR AGENDAMIENTO — extrae preferencias de dia, hora y doctor
const msg = ($json.message_text || "").toLowerCase();

// --- Preferred day ---
const nowUTC = new Date();
const nowLima = new Date(nowUTC.getTime() - 5 * 3600000);
const todayDow = nowLima.getUTCDay();
const tomorrowDow = (todayDow + 1) % 7;

const DAY_WORDS = [
  { words: ["lunes"],                dow: 1 },
  { words: ["martes"],               dow: 2 },
  { words: ["miercoles","miércoles"],dow: 3 },
  { words: ["jueves"],               dow: 4 },
  { words: ["viernes"],              dow: 5 },
  { words: ["sabado","sábado"],      dow: 6 },
  { words: ["domingo"],              dow: 0 },
  { words: ["hoy"],                  dow: todayDow },
  { words: ["mañana","manana"],       dow: tomorrowDow }
];

var preferred_dow = null;
for (var di = 0; di < DAY_WORDS.length; di++) {
  var entry = DAY_WORDS[di];
  for (var wi = 0; wi < entry.words.length; wi++) {
    if (msg.includes(entry.words[wi])) { preferred_dow = entry.dow; break; }
  }
  if (preferred_dow !== null) break;
}

// --- Preferred time window ---
var pref_hour_start = null;
var pref_hour_end   = null;
var hourMatch = msg.match(/\b(\d{1,2})(?::(\d{2}))?\s*(?:pm|p\.m\.|de la tarde|en punto)/);
if (!hourMatch) hourMatch = msg.match(/\b(1[3-9]|2[0-3]):(\d{2})\b/);
if (hourMatch) {
  var h = parseInt(hourMatch[1]);
  if (h < 12 && (msg.includes("pm") || msg.includes("tarde"))) h += 12;
  pref_hour_start = Math.max(9, h - 1);
  pref_hour_end   = Math.min(19, h + 2);
} else if (msg.includes("tarde") || msg.includes("afternoon")) {
  pref_hour_start = 14; pref_hour_end = 19;
} else if (msg.includes("por la mañana") || msg.includes("en la mañana") || msg.includes("por la manana")) {
  pref_hour_start = 9; pref_hour_end = 13;
} else if (msg.includes("mediodia") || msg.includes("mediodía") || msg.includes("medio dia")) {
  pref_hour_start = 12; pref_hour_end = 14;
}

// --- Preferred doctor ---
var preferred_doctor_name = null;
var preferred_specialty   = null;

// Match "con el Dr. García", "con la Dra. López", "con el doctor García"
var doctorMatch = msg.match(/(?:con (?:el |la )?(?:dr\.?|dra\.?|doctor|doctora)\s+)([a-záéíóúüñ]+(?:\s+[a-záéíóúüñ]+)?)/i);
if (!doctorMatch) {
  // Match "doctor García" without "con"
  doctorMatch = msg.match(/(?:dr\.?|dra\.?|doctor|doctora)\s+([a-záéíóúüñ]+)/i);
}
if (doctorMatch) {
  preferred_doctor_name = doctorMatch[1].trim();
}

// Specialty keywords
if (msg.includes("ortodoncia") || msg.includes("brackets") || msg.includes("alineador")) {
  preferred_specialty = "ortodoncia";
} else if (msg.includes("implante")) {
  preferred_specialty = "implantes";
} else if (msg.includes("endodoncia") || msg.includes("conducto")) {
  preferred_specialty = "endodoncia";
} else if (msg.includes("blanqueamiento")) {
  preferred_specialty = "blanqueamiento";
} else if (msg.includes("pediatric") || msg.includes("niño") || msg.includes("niños")) {
  preferred_specialty = "pediatrica";
}

return [{ json: Object.assign({}, $json, {
  escalation_message: "Entiendo que deseas agendar una cita. Buscando horarios disponibles...",
  escalation_reason: "APPOINTMENT_REQUEST",
  escalation_note: "Paciente solicitó: " + $json.intent + "\nMensaje original: " + $json.message_text,
  should_escalate: true,
  preferred_dow: preferred_dow,
  preferred_hour_start: pref_hour_start,
  preferred_hour_end: pref_hour_end,
  preferred_doctor_name: preferred_doctor_name,
  preferred_specialty: preferred_specialty
}) }];

// LEER CITAS SUPABASE — filtra por doctor si hay doctor seleccionado
const ctx = $("Resolver Doctor").item.json;
const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
const clinic_id    = ctx.clinic_id;
const selected_doctor = ctx.selected_doctor;

if (!clinic_id) {
  console.warn(JSON.stringify({ ts: new Date().toISOString(), event: "NO_CLINIC_ID" }));
  return [{ json: { no_appointments: true } }];
}

const now     = new Date();
const in7days = new Date(now.getTime() + 7 * 24 * 3600000);

var url = $env.N8N_SUPABASE_URL + "/rest/v1/appointments"
  + "?clinic_id=eq." + clinic_id
  + "&start_time=gte." + now.toISOString()
  + "&start_time=lte." + in7days.toISOString()
  + "&status=neq.cancelled"
  + "&select=start_time,end_time,doctor_id";

// If specific doctor selected, filter by doctor_id only
if (selected_doctor) {
  url += "&doctor_id=eq." + selected_doctor.id;
}

var appointments = [];
try {
  appointments = await this.helpers.httpRequest({
    method: "GET", url: url,
    headers: { apikey: SERVICE_KEY, Authorization: "Bearer " + SERVICE_KEY },
    json: true
  });
} catch(e) {
  console.error(JSON.stringify({ ts: new Date().toISOString(), event: "APPTS_READ_ERROR", error: e.message }));
}

if (!appointments || appointments.length === 0) {
  return [{ json: { no_appointments: true } }];
}

return appointments.map(function(a) {
  return {
    json: {
      start:     { dateTime: a.start_time },
      end:       { dateTime: a.end_time },
      doctor_id: a.doctor_id || null
    }
  };
});

// PRE-CLASIFICADOR BASADO EN KEYWORDS v4 — with MENU and MENU_SELECTION
const message = ($json.message_text || "").toLowerCase().trim();

// 0. Check if WhatsApp Safe already requested escalation
if ($json.should_escalate === true) {
    return [{ json: Object.assign({}, $json, { intent: "HUMAN", confidence: "high", classified_by: "WHATSAPP_SAFE_ESCALATION", skip_ai: true }) }];
}

// 1. SLOT CONFIRMATION: highest priority (when awaiting slot)
const convLabels = $json.raw_payload && $json.raw_payload.conversation && $json.raw_payload.conversation.labels || [];
const awaitingSlot = convLabels.includes("awaiting_slot");

if (awaitingSlot) {
    const wordMap = { "uno":"1","one":"1","dos":"2","two":"2","tres":"3","three":"3" };
    const cleanMsg = message.replace(/[^a-z0-9 ]/g, "").trim();
    const slotFromWord = wordMap[cleanMsg];
    const slotFromDigit = message.match(/[1-3]/)?.[0];
    const slotDigit = slotFromWord || slotFromDigit || null;
    if (slotDigit) {
        return [{ json: Object.assign({}, $json, { message_text: slotDigit, intent: "CREATE_EVENT", confidence: "high", classified_by: "SLOT_CONFIRMATION_DETECTOR", skip_ai: true }) }];
    }
    // Affirmative response when awaiting slot
    const affirmatives = ["si","sí","yes","ok","dale","de acuerdo","bueno","perfecto","claro","listo","va","quiero","ese","esa"];
    const cleanMsg2 = message.replace(/[^a-z0-9áéíóúñ ]/g, "").trim();
    if (affirmatives.includes(cleanMsg2) || affirmatives.some(function(a) { return cleanMsg2.startsWith(a + " "); })) {
        return [{ json: Object.assign({}, $json, { intent: "CREATE_EVENT", confidence: "high", classified_by: "SLOT_AFFIRMATION_DETECTOR", skip_ai: true }) }];
    }
}

// 2. MENU keywords — show menu
const MENU_KEYWORDS = ["menu","menú","opciones","opcion","inicio","volver","ayuda","start","hola menu","ver opciones"];
for (var mi = 0; mi < MENU_KEYWORDS.length; mi++) {
    if (message === MENU_KEYWORDS[mi] || message.startsWith(MENU_KEYWORDS[mi])) {
        return [{ json: Object.assign({}, $json, { intent: "MENU", confidence: "high", classified_by: "MENU_KEYWORD_DETECTOR", skip_ai: true }) }];
    }
}

// 3. GREETING → show menu
